import { createContext, useContext, useEffect, useState } from 'react'
import { supabase } from './supabase'
import { setUserContext, clearUserContext, addBreadcrumb } from './lib/sentry.js'

const AuthContext = createContext()

export const AuthProvider = ({ children }) => {


    const [user, setUser] = useState(null)
    const [role, setRole] = useState(null)
    const [passwordSet, setPasswordSet] = useState(true) // Default true for existing users
    const [loading, setLoading] = useState(true)

    const fetchRole = async (userId) => {
        try {
            if (!userId) {
                setRole(null)
                setPasswordSet(true)
                return
            }
            // Timeout for fetchRole specifically
            const timeoutPromise = new Promise((_, reject) =>
                setTimeout(() => reject(new Error('Timeout')), 5000)
            )

            const fetchPromise = supabase
                .from('profiles')
                .select('role, password_set')
                .eq('id', userId)
                .single()

            const { data, error } = await Promise.race([fetchPromise, timeoutPromise])

            if (error) {
                console.error('Error fetching role:', error)
                setRole('user')
                setPasswordSet(true) // Assume set if we can't check
            } else {
                setRole(data?.role || 'user')
                // password_set might be null for old users, treat as true
                setPasswordSet(data?.password_set !== false)
            }
        } catch (e) {
            console.error('Exception/Timeout fetching role:', e)
            setRole('user')
            setPasswordSet(true)
        }
    }

    useEffect(() => {
        let mounted = true

        // Global safety timeout
        const safetyTimer = setTimeout(() => {
            if (mounted) {
                console.warn('Auth loading timed out, forcing render')
                setLoading(false)
            }
        }, 5000)

        const initAuth = async () => {

            try {
                const { data: { session }, error } = await supabase.auth.getSession()
                if (error) throw error

                if (mounted) {
                    setUser(session?.user ?? null)
                    if (session?.user) {
                        await fetchRole(session.user.id)
                        // Set Sentry user context for error tracking
                        setUserContext(session.user)
                        addBreadcrumb('auth', 'User logged in')
                    } else {
                        clearUserContext()
                    }
                }
            } catch (error) {
                console.error('Auth initialization error:', error)
            } finally {
                if (mounted) setLoading(false)
            }
        }

        initAuth()



        const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
            if (mounted) {
                setUser(session?.user ?? null)
                if (session?.user) {
                    fetchRole(session.user.id)
                    // Update Sentry user context
                    setUserContext(session.user)
                    addBreadcrumb('auth', `Auth state changed: ${_event}`)
                } else {
                    setRole(null)
                    clearUserContext()
                    addBreadcrumb('auth', 'User logged out')
                }
                setLoading(false)
            }
        })

        return () => {
            mounted = false
            clearTimeout(safetyTimer)
            subscription.unsubscribe()
        }
    }, [])



    const isAdmin = role === 'admin'

    // Function to refresh password_set status after user sets their password
    const refreshPasswordSet = () => {
        setPasswordSet(true)
    }

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900"></div>
                <span className="ml-3 text-gray-500 font-medium">Laden...</span>
            </div>
        )
    }

    return (
        <AuthContext.Provider value={{ user, role, isAdmin, loading, passwordSet, refreshPasswordSet }}>
            {children}
        </AuthContext.Provider>
    )
}

export const useAuth = () => useContext(AuthContext)

import { Calendar, List, User, Plane, Shield } from 'lucide-react'

// Badge component for notification dots
function Badge({ count, dot = false }) {
    if (!count && !dot) return null

    if (dot) {
        return (
            <span className="absolute -top-0.5 -right-0.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-white" />
        )
    }

    return (
        <span className="absolute -top-1 -right-2 min-w-[18px] h-[18px] bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center border-2 border-white">
            {count > 99 ? '99+' : count}
        </span>
    )
}

// NavItem component for cleaner code
function NavItem({ id, icon: Icon, label, isActive, onClick, badge }) {
    return (
        <button
            onClick={() => onClick(id)}
            className={`flex flex-col items-center p-2 relative ${isActive ? 'text-black' : 'text-gray-400'}`}
        >
            <div className="relative">
                <Icon size={24} />
                <Badge count={badge?.count} dot={badge?.dot} />
            </div>
            <span className="text-[10px] font-medium mt-1">{label}</span>
        </button>
    )
}

