import { useState, useEffect } from 'react'
import { WifiOff, Wifi } from 'lucide-react'

/**
 * OfflineIndicator Component
 * 
 * Displays a visual banner when the user is offline.
 * Shows a brief "back online" message when connection is restored.
 * 
 * Features:
 * - Monitors navigator.onLine status
 * - Listens for online/offline events
 * - Animated slide-in/out transitions
 * - German language messages
 */
export default function OfflineIndicator() {
    const [isOnline, setIsOnline] = useState(navigator.onLine)
    const [showReconnected, setShowReconnected] = useState(false)
    const [wasOffline, setWasOffline] = useState(false)

    useEffect(() => {
        const handleOnline = () => {
            setIsOnline(true)
            // Show "back online" message if we were previously offline
            if (wasOffline) {
                setShowReconnected(true)
                // Hide after 3 seconds
                setTimeout(() => setShowReconnected(false), 3000)
            }
            setWasOffline(false)
        }

        const handleOffline = () => {
            setIsOnline(false)
            setWasOffline(true)
        }

        window.addEventListener('online', handleOnline)
        window.addEventListener('offline', handleOffline)

        return () => {
            window.removeEventListener('online', handleOnline)
            window.removeEventListener('offline', handleOffline)
        }
    }, [wasOffline])

    // Nothing to show if online and not showing reconnection message
    if (isOnline && !showReconnected) return null

    return (
        <div
            className={`
                fixed top-0 left-0 right-0 z-[100] 
                flex items-center justify-center gap-2 
                py-2 px-4 text-sm font-medium
                transform transition-all duration-300 ease-out
                ${isOnline
                    ? 'bg-green-500 text-white translate-y-0'
                    : 'bg-gray-800 text-white translate-y-0'
                }
            `}
            role="alert"
            aria-live="polite"
        >
            {isOnline ? (
                <>
                    <Wifi size={16} className="animate-pulse" />
                    <span>Verbindung wiederhergestellt</span>
                </>
            ) : (
                <>
                    <WifiOff size={16} />
                    <span>Du bist offline ÔÇô ├änderungen werden nicht gespeichert</span>
                </>
            )}
        </div>
    )
}

/**
 * useOnlineStatus Hook
 * 
 * Simple hook to get current online status.
 * Can be used in components that need to react to connectivity changes.
 * 
 * Usage:
 *   const isOnline = useOnlineStatus()
 *   if (!isOnline) { // disable submit button }
 */
export function useOnlineStatus() {
    const [isOnline, setIsOnline] = useState(navigator.onLine)

    useEffect(() => {
        const handleOnline = () => setIsOnline(true)
        const handleOffline = () => setIsOnline(false)

        window.addEventListener('online', handleOnline)
        window.addEventListener('offline', handleOffline)

        return () => {
            window.removeEventListener('online', handleOnline)
            window.removeEventListener('offline', handleOffline)
        }
    }, [])

    return isOnline
}

/**
 * Toast Notification Component
 * 
 * Simple toast notification for displaying user-friendly error messages
 * and success notifications.
 */

import { useState, useEffect, createContext, useContext, useCallback } from 'react'
import { X, AlertCircle, CheckCircle, AlertTriangle, Info } from 'lucide-react'

// Context for toast notifications
const ToastContext = createContext(null)

// Toast types with their styling
const ToastStyles = {
    error: {
        bg: 'bg-red-50 border-red-200',
        icon: AlertCircle,
        iconColor: 'text-red-500',
        titleColor: 'text-red-800',
        messageColor: 'text-red-600'
    },
    success: {
        bg: 'bg-green-50 border-green-200',
        icon: CheckCircle,
        iconColor: 'text-green-500',
        titleColor: 'text-green-800',
        messageColor: 'text-green-600'
    },
    warning: {
        bg: 'bg-yellow-50 border-yellow-200',
        icon: AlertTriangle,
        iconColor: 'text-yellow-500',
        titleColor: 'text-yellow-800',
        messageColor: 'text-yellow-600'
    },
    info: {
        bg: 'bg-blue-50 border-blue-200',
        icon: Info,
        iconColor: 'text-blue-500',
        titleColor: 'text-blue-800',
        messageColor: 'text-blue-600'
    }
}

// Single Toast component
function Toast({ id, type = 'info', title, message, duration = 5000, onDismiss }) {
    const style = ToastStyles[type] || ToastStyles.info
    const Icon = style.icon

    useEffect(() => {
        if (duration > 0) {
            const timer = setTimeout(() => onDismiss(id), duration)
            return () => clearTimeout(timer)
        }
    }, [id, duration, onDismiss])

    return (
        <div
            className={`${style.bg} border rounded-xl p-4 shadow-lg flex items-start gap-3 animate-in slide-in-from-right duration-300 max-w-sm`}
            role="alert"
        >
            <Icon className={`${style.iconColor} flex-shrink-0 mt-0.5`} size={20} />
            <div className="flex-1 min-w-0">
                <h4 className={`font-bold ${style.titleColor} text-sm`}>{title}</h4>
                {message && (
                    <p className={`${style.messageColor} text-sm mt-1`}>{message}</p>
                )}
            </div>
            <button
                onClick={() => onDismiss(id)}
                className="text-gray-400 hover:text-gray-600 transition-colors"
                aria-label="Schlie├ƒen"
            >
                <X size={18} />
            </button>
        </div>
    )
}

// Toast Container - renders at the top-right of the screen
function ToastContainer({ toasts, onDismiss }) {
    if (toasts.length === 0) return null

    return (
        <div className="fixed top-4 right-4 z-[9999] flex flex-col gap-2">
            {toasts.map(toast => (
                <Toast
                    key={toast.id}
                    {...toast}
                    onDismiss={onDismiss}
                />
            ))}
        </div>
    )
}

// Toast Provider - wraps the app
export function ToastProvider({ children }) {
    const [toasts, setToasts] = useState([])

    const addToast = useCallback((toast) => {
        const id = Date.now() + Math.random()
        setToasts(prev => [...prev, { id, ...toast }])
        return id
    }, [])

    const dismissToast = useCallback((id) => {
        setToasts(prev => prev.filter(t => t.id !== id))
    }, [])

    const showError = useCallback((title, message) => {
        return addToast({ type: 'error', title, message })
    }, [addToast])

    const showSuccess = useCallback((title, message) => {
        return addToast({ type: 'success', title, message })
    }, [addToast])

    const showWarning = useCallback((title, message) => {
        return addToast({ type: 'warning', title, message })
    }, [addToast])

    const showInfo = useCallback((title, message) => {
        return addToast({ type: 'info', title, message })
    }, [addToast])

    // Clear all toasts
    const clearAll = useCallback(() => {
        setToasts([])
    }, [])

    const value = {
        toasts,
        addToast,
        dismissToast,
        showError,
        showSuccess,
        showWarning,
        showInfo,
        clearAll
    }

    return (
        <ToastContext.Provider value={value}>
            {children}
            <ToastContainer toasts={toasts} onDismiss={dismissToast} />
        </ToastContext.Provider>
    )
}

// Hook to use toast notifications
export function useToast() {
    const context = useContext(ToastContext)
    if (!context) {
        throw new Error('useToast must be used within a ToastProvider')
    }
    return context
}

// Utility function to show error from errorHandler
export function showErrorToast(toast, friendlyError) {
    if (!toast || !friendlyError) return
    toast.showError(friendlyError.title, friendlyError.message)
}

export default ToastProvider

import { createContext, useContext, useState, useEffect } from 'react'
import { supabase } from '../supabase'
import { FEATURE_MULTI_TENANCY } from '../utils/featureFlags'

/**
 * ShiftTemplateContext
 * 
 * Provides shift templates from the database to all components.
 * When FEATURE_MULTI_TENANCY is false, returns legacy hardcoded templates.
 * 
 * Usage:
 *   const { templates, getTemplate, loading } = useShiftTemplates()
 *   const ndTemplate = getTemplate('ND')
 */

const ShiftTemplateContext = createContext({
    templates: [],
    loading: true,
    error: null,
    getTemplate: () => null,
    getDefaultTimes: () => ({ start: null, end: null }),
})

// Legacy templates for fallback (matches shiftDefaults.js)
const LEGACY_TEMPLATES = [
    {
        code: 'TD1',
        name: 'Tagdienst 1',
        start_time: '07:30',
        end_time: '14:30',
        spans_midnight: false,
        color: '#22c55e',
        has_standby: false,
        weekday_rules: {
            saturday: { start: '09:30', end: '14:30' },
            sunday: { start: '09:30', end: '14:30' },
            holiday: { start: '09:30', end: '14:30' },
        },
    },
    {
        code: 'TD2',
        name: 'Tagdienst 2',
        start_time: '14:00',
        end_time: '19:30',
        spans_midnight: false,
        color: '#3b82f6',
        has_standby: false,
        weekday_rules: {},
    },
    {
        code: 'ND',
        name: 'Nachtdienst',
        start_time: '19:00',
        end_time: '08:00',
        spans_midnight: true,
        color: '#6366f1',
        has_standby: true,
        standby_start: '00:30',
        standby_end: '06:00',
        standby_factor: 0.5,
        interruption_min_minutes: 30,
        weekday_rules: {
            friday: { end: '10:00' },
            saturday: { end: '10:00' },
        },
    },
    {
        code: 'DBD',
        name: 'Doppeltbesetzter Dienst',
        start_time: '20:00',
        end_time: '00:00',
        spans_midnight: true,
        color: '#8b5cf6',
        has_standby: false,
        weekday_rules: {},
    },
    {
        code: 'TEAM',
        name: 'Teamsitzung',
        start_time: '09:30',
        end_time: '11:30',
        spans_midnight: false,
        color: '#f59e0b',
        has_standby: false,
        weekday_rules: {},
    },
    {
        code: 'FORTBILDUNG',
        name: 'Fortbildung',
        start_time: '09:00',
        end_time: '17:00',
        spans_midnight: false,
        color: '#ec4899',
        has_standby: false,
        weekday_rules: {},
    },
]

export function ShiftTemplateProvider({ children }) {
    const [templates, setTemplates] = useState([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState(null)

    useEffect(() => {
        const loadTemplates = async () => {
            // If feature flag is off, use legacy templates
            if (!FEATURE_MULTI_TENANCY) {
                setTemplates(LEGACY_TEMPLATES)
                setLoading(false)
                return
            }

            try {
                const { data, error: fetchError } = await supabase
                    .from('shift_templates')
                    .select('*')
                    .eq('is_active', true)
                    .order('sort_order')

                if (fetchError) throw fetchError

                // Parse weekday_rules if it's a string
                const parsed = (data || []).map(t => ({
                    ...t,
                    weekday_rules: typeof t.weekday_rules === 'string'
                        ? JSON.parse(t.weekday_rules)
                        : (t.weekday_rules || {}),
                }))

                setTemplates(parsed)
            } catch (err) {
                console.error('Failed to load shift templates:', err)
                setError(err)
                // Fallback to legacy on error
                setTemplates(LEGACY_TEMPLATES)
            } finally {
                setLoading(false)
            }
        }

        loadTemplates()
    }, [])

    /**
     * Get a template by its code
     */
    const getTemplate = (code) => {
        if (!code) return null
        return templates.find(t => t.code?.toUpperCase() === code.toUpperCase()) || null
    }

    /**
     * Get default start/end times for a shift type on a given date
     * Respects weekday_rules for special times on weekends/holidays
     */
    const getDefaultTimes = (dateStr, code, holidays = []) => {
        const template = getTemplate(code)
        if (!template) return { start: null, end: null }

        const date = new Date(dateStr)
        const dayName = date.toLocaleDateString('en-US', { weekday: 'long' }).toLowerCase()
        const _dayOfWeek = date.getDay() // 0=Sunday, 6=Saturday

        // Check for holiday
        const isHoliday = holidays.some(h => {
            const hDate = new Date(h.date || h)
            return hDate.toDateString() === date.toDateString()
        })

        // Determine which rules to apply
        let startTime = template.start_time
        let endTime = template.end_time

        const rules = template.weekday_rules || {}

        // Priority: Holiday > Specific Day > Default
        if (isHoliday && rules.holiday) {
            startTime = rules.holiday.start || startTime
            endTime = rules.holiday.end || endTime
        } else if (rules[dayName]) {
            startTime = rules[dayName].start || startTime
            endTime = rules[dayName].end || endTime
        }

        // Convert time strings to full datetime strings
        const createDateTime = (timeStr, addDays = 0) => {
            const [hours, minutes] = timeStr.split(':').map(Number)
            const d = new Date(date)
            d.setHours(hours, minutes, 0, 0)
            if (addDays > 0) d.setDate(d.getDate() + addDays)
            return d
        }

        const start = createDateTime(startTime)
        let end = createDateTime(endTime)

        // If spans midnight, add 1 day to end time
        if (template.spans_midnight) {
            end = createDateTime(endTime, 1)
        }

        return { start, end }
    }

    const value = {
        templates,
        loading,
        error,
        getTemplate,
        getDefaultTimes,
    }

    return (
        <ShiftTemplateContext.Provider value={value}>
            {children}
        </ShiftTemplateContext.Provider>
    )
}

export function useShiftTemplates() {
    const context = useContext(ShiftTemplateContext)
    if (!context) {
        throw new Error('useShiftTemplates must be used within a ShiftTemplateProvider')
    }
    return context
}

export default ShiftTemplateContext

/**
 * DSGVO Anonymization Tests
 * 
 * CRITICAL: These tests verify that sensitive health data (Krankmeldungen)
 * is properly anonymized when displayed to colleagues.
 * 
 * Austrian data protection law requires that health information
 * is only visible to the affected person and authorized personnel (Admins).
 */
import { describe, it, expect, vi } from 'vitest'

// =============================================================================
// LOCAL TEST HELPERS (avoid importing from test-utils.jsx for pure unit tests)
// =============================================================================

const mockUsers = {
    admin: {
        id: 'admin-uuid-123',
        email: 'admin@test.local',
        role: 'admin',
        full_name: 'Test Admin'
    },
    employee: {
        id: 'employee-uuid-456',
        email: 'mitarbeiter@test.local',
        role: 'user',
        full_name: 'Max Mustermann'
    },
    partTime: {
        id: 'parttime-uuid-789',
        email: 'teilzeit@test.local',
        role: 'user',
        full_name: 'Lisa Teilzeit'
    }
}

const rlsTestData = {
    time_entries: [
        {
            id: 'te-1',
            user_id: mockUsers.employee.id,
            entry_date: '2025-01-10',
            calculated_hours: 8.5
        }
    ]
}

function assertAnonymized(element, sensitiveTerms = ['Krank', 'Krankenstand', 'krank']) {
    const text = element.textContent || ''
    sensitiveTerms.forEach(term => {
        if (text.toLowerCase().includes(term.toLowerCase())) {
            throw new Error(`DSGVO VIOLATION: Found sensitive term "${term}" in output: "${text}"`)
        }
    })
}

// =============================================================================
// UNIT TESTS: Anonymization Helper Functions
// =============================================================================

describe('DSGVO: Anonymization Functions', () => {

    describe('assertAnonymized helper', () => {
        it('passes when no sensitive terms are present', () => {
            const mockElement = { textContent: 'Mitarbeiter ist abwesend von 15.01. bis 17.01.' }
            expect(() => assertAnonymized(mockElement)).not.toThrow()
        })

        it('throws DSGVO VIOLATION for "Krank" in text', () => {
            const mockElement = { textContent: 'Max ist Krank von 15.01. bis 17.01.' }
            expect(() => assertAnonymized(mockElement)).toThrow('DSGVO VIOLATION')
        })

        it('throws for "Krankenstand" (case insensitive)', () => {
            const mockElement = { textContent: 'Status: krankenstand' }
            expect(() => assertAnonymized(mockElement)).toThrow('DSGVO VIOLATION')
        })

        it('allows custom sensitive terms', () => {
            const mockElement = { textContent: 'Gehalt: 5000Ôé¼' }
            expect(() => assertAnonymized(mockElement, ['Gehalt', 'Lohn'])).toThrow('DSGVO VIOLATION')
        })
    })
})

// =============================================================================
// PUSH NOTIFICATION ANONYMIZATION
// =============================================================================

describe('DSGVO: Push Notification Content', () => {
    /**
     * The push notification edge function should NEVER include:
     * - The word "krank" or "Krankenstand"
     * - The name of the sick person
     * - Any health-related information
     * 
     * CORRECT: "Dienstausfall! Kannst du im Zeitraum 15.01. - 17.01. einspringen?"
     * WRONG: "Max ist krank vom 15.01. - 17.01."
     */

    it('notification message format should be anonymous', () => {
        // Simulated notification message from edge function
        const notificationMessage = buildSickNotificationMessage({
            startDate: '2025-01-15',
            endDate: '2025-01-17'
        })

        // Must NOT contain sensitive information
        expect(notificationMessage).not.toContain('krank')
        expect(notificationMessage).not.toContain('Krank')
        expect(notificationMessage).not.toContain('Krankenstand')

        // Should contain generic "Dienstausfall"
        expect(notificationMessage).toContain('Dienstausfall')
    })

    it('notification should show date range correctly', () => {
        const message = buildSickNotificationMessage({
            startDate: '2025-01-15',
            endDate: '2025-01-17'
        })

        expect(message).toContain('15.01.')
        expect(message).toContain('17.01.')
    })

    it('single day notification shows only one date', () => {
        const message = buildSickNotificationMessage({
            startDate: '2025-01-15',
            endDate: '2025-01-15'
        })

        // Should show "am 15.01." not "vom 15.01. - 15.01."
        expect(message).toContain('am 15.01.')
        expect(message).not.toContain(' - ')
    })
})

// Helper to simulate the notification message builder
function buildSickNotificationMessage({ startDate, endDate }) {
    const formatDate = (dateStr) => {
        const [year, month, day] = dateStr.split('-')
        return `${day}.${month}.`
    }

    const start = formatDate(startDate)
    const end = formatDate(endDate)

    if (startDate === endDate) {
        return `Dienstausfall! Kannst du am ${start} einspringen?`
    }
    return `Dienstausfall! Kannst du im Zeitraum ${start} - ${end} einspringen?`
}

