            target: NaN,
            actual: 160,
            vacation: 16,
            diff: 0,
            carryover: 10,
            correction: 0,
            total: 10
        }

        // Mock console to avoid noise
        const spy = vi.spyOn(console, 'log').mockImplementation(() => { })

        const result = withBalanceVerification(invalidBalance, 'TestContext')
        expect(result).toBe(invalidBalance)

        spy.mockRestore()
    })
})
